import 'package:flutter/material.dart';

class ProductCard extends StatelessWidget {
  final dynamic product;
  final Widget image;
  final Function(BuildContext, dynamic, int, double, String, Function) onFinalizeNegotiation;
  final Function(BuildContext, dynamic, int, double, String, Function) onRefuseNegotiation;
  final Function(BuildContext, dynamic) onCounterProposal;
  final Function(BuildContext, dynamic) onWithdraw;
  final Function(dynamic, BuildContext) onDownloadContract;
  final Color cardColor;
  final Color borderColor;
  final Color negotiationCardColor;
  final double borderRadius;

  const ProductCard({
    super.key,
    required this.product,
    required this.image,
    required this.onFinalizeNegotiation,
    required this.onRefuseNegotiation,
    required this.onCounterProposal,
    required this.onWithdraw,
    required this.onDownloadContract,
    this.cardColor = const Color(0xFFE7F7E9),
    this.borderColor = const Color(0xFF015F0F),
    this.negotiationCardColor = const Color(0xFFF5FDF7),
    this.borderRadius = 8.0,
  });

  @override
  Widget build(BuildContext context) {
    return Card(
      margin: const EdgeInsets.all(10),
      color: cardColor,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(borderRadius),
        side: BorderSide(color: borderColor, width: 2),
      ),
      child: Padding(
        padding: const EdgeInsets.all(8.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            _buildProductHeader(),
            const SizedBox(height: 8),
            const Text('Negociações:', style: TextStyle(fontWeight: FontWeight.bold)),
            ..._buildNegotiationsList(context),
          ],
        ),
      ),
    );
  }

  Widget _buildProductHeader() {
    return Row(
      children: [
        Expanded(flex: 2, child: image),
        Expanded(
          flex: 3,
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                product.tipo ?? 'Sem descrição',
                style: const TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                ),
              ),
              Text(
                'Lote: ${product.id}',
                style: const TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                ),
              ),
              Text('Quantidade: ${product.qtdSacos} sacos'),
              Text('Data Retirada: ${product.dtRetirada}'),
              Text('Descrição: ${product.descricao}'),
            ],
          ),
        ),
      ],
    );
  }

  List<Widget> _buildNegotiationsList(BuildContext context) {
    return List.generate((product.negociacoes as List).length, (i) {
      final negotiation = product.negociacoes[i];
      return NegotiationCard(
        negotiation: negotiation,
        borderColor: borderColor,
        cardColor: negotiationCardColor,
        borderRadius: borderRadius,
        onFinalize: () => onFinalizeNegotiation(
          context,
          negotiation.id!,
          negotiation.qtdSacos!,
          negotiation.vlrSacos!,
          negotiation.id!.toString(),
          () {}, // Add fetchProducts callback if needed
        ),
        onRefuse: () => onRefuseNegotiation(
          context,
          negotiation.id!,
          negotiation.qtdSacos!,
          negotiation.vlrSacos!,
          negotiation.id!.toString(),
          () {}, // Add fetchProducts callback if needed
        ),
        onCounterProposal: () => onCounterProposal(context, negotiation),
        onWithdraw: () => onWithdraw(context, negotiation),
        onDownloadContract: () => onDownloadContract(negotiation.id, context),
      );
    });
  }
}

class NegotiationCard extends StatelessWidget {
  final dynamic negotiation;
  final Color borderColor;
  final Color cardColor;
  final double borderRadius;
  final VoidCallback onFinalize;
  final VoidCallback onRefuse;
  final VoidCallback onCounterProposal;
  final VoidCallback onWithdraw;
  final VoidCallback onDownloadContract;

  const NegotiationCard({
    super.key,
    required this.negotiation,
    required this.borderColor,
    required this.cardColor,
    required this.borderRadius,
    required this.onFinalize,
    required this.onRefuse,
    required this.onCounterProposal,
    required this.onWithdraw,
    required this.onDownloadContract,
  });

  @override
  Widget build(BuildContext context) {
    return Card(
      margin: const EdgeInsets.symmetric(vertical: 4.0),
      color: cardColor,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(borderRadius),
        side: BorderSide(color: borderColor, width: 1.5),
      ),
      child: Padding(
        padding: const EdgeInsets.all(8.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            _buildNegotiationDetails(),
            const SizedBox(height: 8),
            _buildActionButtons(),
          ],
        ),
      ),
    );
  }

  Widget _buildNegotiationDetails() {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _buildDetailItem('Comprador ID: ${negotiation.compradorId}'),
        _buildDetailItem('Quantidade: ${negotiation.qtdSacos}'),
        _buildDetailItem('Valor por saco: R\$${negotiation.vlrSacos}'),
        _buildDetailItem(
          'Status: ${getStatusText(negotiation.status)} / ${getTipoText(negotiation.tipo)}',
        ),
      ],
    );
  }

  Widget _buildDetailItem(String text) {
    return SizedBox(
      width: double.infinity,
      child: Text(text, style: const TextStyle(fontSize: 14)),
    );
  }

  Widget _buildActionButtons() {
    if (negotiation.tipo == 'P' || negotiation.tipo == 'C') {
      return _buildProposalButtons();
    } else if (negotiation.tipo == 'A') {
      return _buildAcceptanceButtons();
    } else if (negotiation.tipo == 'X') {
      return _buildCounterProposalButton();
    } else if (negotiation.tipo == 'F') {
      return _buildFinalizedButtons();
    }
    return const SizedBox.shrink();
  }

  Widget _buildProposalButtons() {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
      children: [
        _buildIconButton(Icons.check, 'Aceitar', Colors.green, onFinalize),
        _buildIconButton(Icons.close, 'Recusar', Colors.red, onRefuse),
        _buildIconButton(Icons.handshake, 'Contra Proposta', Colors.green, onCounterProposal),
      ],
    );
  }

  Widget _buildAcceptanceButtons() {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
      children: [
        _buildIconButton(Icons.edit_document, 'Assinar Contrato', const Color(0xFF015F0F), () {}),
        _buildIconButton(Icons.cancel, 'Desistir', Colors.red, onWithdraw),
      ],
    );
  }

  Widget _buildCounterProposalButton() {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
      children: [
        _buildIconButton(Icons.handshake, 'Contra Proposta', Colors.green, onCounterProposal),
      ],
    );
  }

  Widget _buildFinalizedButtons() {
    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
      children: [
        _buildIconButton(Icons.download, 'Download Contrato', Colors.green, onDownloadContract),
        _buildIconButton(Icons.star, 'Avaliar', Colors.orange, () {}),
      ],
    );
  }

  Widget _buildIconButton(IconData icon, String label, Color color, VoidCallback onPressed) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        IconButton(
          icon: Icon(icon, color: color),
          onPressed: onPressed,
        ),
        Text(label, style: TextStyle(fontSize: 12, color: Colors.black)),
      ],
    );
  }

  // Add your status translation methods here
  String getStatusText(String status) {
    // Implement your status translation logic
    return status;
  }

  String getTipoText(String tipo) {
    // Implement your type translation logic
    return tipo;
  }
}
